    "cases.update_the_programme_and_reforecast.step.slippage.out.causes": "遅延の原因",
    "cases.update_the_programme_and_reforecast.step.slippage.out.slippage": "ベースラインからの遅れ",
    "cases.update_the_programme_and_reforecast.step.slippage.title": "ベースラインに対する遅れを把握する",
