    "change_intelligence.delay.tile.elevated": "やや高",
    "change_intelligence.delay.tile.low": "低",
    "change_intelligence.delay.empty_title": "オープン中の変更なし",
    "change_intelligence.delay.empty_desc": "今すぐ遅延リスクを採点するオープン中の変更はありません。",
    "change_intelligence.delay.risk_pct": "リスク{{pct}}%",
    "change_intelligence.delay.overdue": "超過",
